
/*************trigActualizarIngresosInventario*****************/
WITH param AS (     SELECT     9 as ide_geani,     8019 as ide_bocam,     4 as ide_boubi,     1 as ide_inttr,     3 as ide_inttr_t )
, ingresos AS (  SELECT   bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam,   bodt_ingreso_egreso.ide_boubi,   count(bodt_ingreso_egreso.ide_geani),   SUM (bodt_ingreso_egreso_det.cantidad_inegd) AS cantidad,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inegd) AS costo_acumulado_ingreso,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inc_iva_inegd) AS costo_acumulado_ingreso_inc_iva,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.valor_existencia_inegd) AS costo_acumulado_ingreso_valor_existencia  FROM bodt_ingreso_egreso_det  JOIN bodt_ingreso_egreso ON bodt_ingreso_egreso.ide_ingeg = bodt_ingreso_egreso_det.ide_ingeg  WHERE      bodt_ingreso_egreso.ide_geani= (SELECT ide_geani FROM param)     AND bodt_ingreso_egreso_det.ide_bocam = (SELECT ide_bocam FROM param)     AND bodt_ingreso_egreso.ide_inttr = (SELECT ide_inttr FROM param)     AND bodt_ingreso_egreso.ide_boubi = (SELECT ide_boubi FROM param)     AND bodt_ingreso_egreso.activo_ingeg = true  GROUP BY bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam, bodt_ingreso_egreso.ide_boubi )
, ingresos_t AS (  SELECT   bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam,   bodt_ingreso_egreso.ide_boubi,   count(bodt_ingreso_egreso.ide_geani),   SUM (bodt_ingreso_egreso_det.cantidad_inegd) AS cantidad,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inegd) AS costo_acumulado_ingreso,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inc_iva_inegd) AS costo_acumulado_ingreso_inc_iva,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.valor_existencia_inegd) AS costo_acumulado_ingreso_valor_existencia  FROM bodt_ingreso_egreso_det  JOIN bodt_ingreso_egreso ON bodt_ingreso_egreso.ide_ingeg = bodt_ingreso_egreso_det.ide_ingeg  WHERE      bodt_ingreso_egreso.ide_geani= (SELECT ide_geani FROM param)     AND bodt_ingreso_egreso_det.ide_bocam = (SELECT ide_bocam FROM param)     AND bodt_ingreso_egreso.ide_inttr = (SELECT ide_inttr_t FROM param)     AND bodt_ingreso_egreso.ide_boubi = (SELECT ide_boubi FROM param)     AND bodt_ingreso_egreso.activo_ingeg = true  GROUP BY bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam, bodt_ingreso_egreso.ide_boubi ) 
SELECT * FROM ingresos_t


 UPDATE bodt_bodega_inventario SET 
 cantidad_ingreso_boinv = COALESCE(ingresos.cantidad, 0), 
 costo_ingreso_sin_iva_boinv = COALESCE(ingresos.costo_acumulado_ingreso,0) ,  
 costo_ingreso_inc_iva_boinv = COALESCE(ingresos.costo_acumulado_ingreso_inc_iva,0),  
 costo_ingreso_boinv = COALESCE(ingresos.costo_acumulado_ingreso_valor_existencia,0) ,   cantidad_ingreso_t_boinv = COALESCE(ingresos_t.cantidad, 0), costo_ingreso_t_sin_iva_boinv = COALESCE(ingresos_t.costo_acumulado_ingreso,0) ,  costo_ingreso_t_inc_iva_boinv = COALESCE(ingresos_t.costo_acumulado_ingreso_inc_iva,0),  costo_ingreso_t_boinv = COALESCE(ingresos_t.costo_acumulado_ingreso_valor_existencia,0) ,  usuario_actua = 'devuser', fecha_actua = '2025-08-24', hora_actua = '00:27:32' FROM ingresos FULL OUTER JOIN ingresos_t ON ingresos.ide_bocam = ingresos_t.ide_bocam AND ingresos.ide_boubi = ingresos_t.ide_boubi AND ingresos.ide_geani = ingresos_t.ide_geani FULL OUTER JOIN param ON param.ide_geani = ingresos.ide_geani AND ingresos.ide_bocam = param.ide_bocam AND ingresos.ide_boubi = param.ide_boubi WHERE  bodt_bodega_inventario.ide_geani = (SELECT ide_geani FROM param) AND bodt_bodega_inventario.ide_bocam = (SELECT ide_bocam FROM param) AND bodt_bodega_inventario.ide_boubi = (SELECT ide_boubi FROM param)  

/********************trigActualizarEgresosInventario*******************************/

WITH  param AS (     SELECT      9 as ide_geani,      8019 as ide_bocam,     4 as ide_boubi,     2 as ide_inttr,     4 as ide_inttr_t ), egresos AS (  SELECT   bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam,   bodt_ingreso_egreso.ide_boubi,   count(bodt_ingreso_egreso.ide_geani),   SUM (bodt_ingreso_egreso_det.cantidad_inegd) AS cantidad,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inegd) AS costo_acumulado_ingreso,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inc_iva_inegd) AS costo_acumulado_ingreso_inc_iva,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.valor_existencia_inegd) AS costo_acumulado_ingreso_valor_existencia  FROM bodt_ingreso_egreso_det   JOIN bodt_ingreso_egreso ON bodt_ingreso_egreso.ide_ingeg = bodt_ingreso_egreso_det.ide_ingeg   WHERE       bodt_ingreso_egreso.ide_geani = (SELECT ide_geani FROM param)     AND bodt_ingreso_egreso_det.ide_bocam= (SELECT ide_bocam FROM param)     AND bodt_ingreso_egreso.ide_inttr = (SELECT ide_inttr FROM param)     AND bodt_ingreso_egreso.ide_boubi = (SELECT ide_boubi FROM param)     AND bodt_ingreso_egreso.activo_ingeg = true   GROUP BY bodt_ingreso_egreso.ide_geani,    bodt_ingreso_egreso_det.ide_bocam, bodt_ingreso_egreso.ide_boubi ), egresos_t AS (  SELECT   bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam,   bodt_ingreso_egreso.ide_boubi,   count(bodt_ingreso_egreso.ide_geani),   SUM (bodt_ingreso_egreso_det.cantidad_inegd) AS cantidad,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inegd) AS costo_acumulado_ingreso,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.costo_unitario_inc_iva_inegd) AS costo_acumulado_ingreso_inc_iva,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.valor_existencia_inegd) AS costo_acumulado_ingreso_valor_existencia  FROM bodt_ingreso_egreso_det   JOIN bodt_ingreso_egreso ON bodt_ingreso_egreso.ide_ingeg = bodt_ingreso_egreso_det.ide_ingeg   WHERE       bodt_ingreso_egreso.ide_geani = (SELECT ide_geani FROM param)     AND bodt_ingreso_egreso_det.ide_bocam= (SELECT ide_bocam FROM param)     AND bodt_ingreso_egreso.ide_inttr = (SELECT ide_inttr_t FROM param)     AND bodt_ingreso_egreso.ide_boubi = (SELECT ide_boubi FROM param)     AND bodt_ingreso_egreso.activo_ingeg = true   GROUP BY bodt_ingreso_egreso.ide_geani,    bodt_ingreso_egreso_det.ide_bocam, bodt_ingreso_egreso.ide_boubi ),  egresos_baja AS (  SELECT   bodt_ingreso_egreso.ide_geani,   bodt_ingreso_egreso_det.ide_bocam,   bodt_ingreso_egreso.ide_boubi,   count(bodt_ingreso_egreso.ide_geani),   SUM (bodt_ingreso_egreso_det.cantidad_inegd) AS cantidad,   SUM (bodt_ingreso_egreso_det.cantidad_inegd * bodt_ingreso_egreso_det.valor_existencia_inegd) AS costo_acumulado_egreso_valor_existencia  FROM bodt_ingreso_egreso_det   JOIN bodt_ingreso_egreso ON bodt_ingreso_egreso.ide_ingeg = bodt_ingreso_egreso_det.ide_ingeg   WHERE       bodt_ingreso_egreso.ide_geani = (SELECT ide_geani FROM param)     AND bodt_ingreso_egreso_det.ide_bocam= (SELECT ide_bocam FROM param)     AND bodt_ingreso_egreso.ide_inttr = 6     AND bodt_ingreso_egreso.ide_boubi = (SELECT ide_boubi FROM param)     AND bodt_ingreso_egreso.activo_ingeg = true   GROUP BY bodt_ingreso_egreso.ide_geani,    bodt_ingreso_egreso_det.ide_bocam, bodt_ingreso_egreso.ide_boubi )    UPDATE bodt_bodega_inventario  SET  cantidad_egreso_boinv = COALESCE(egresos.cantidad, 0), costo_egreso_sin_iva_boinv = COALESCE(egresos.costo_acumulado_ingreso,0),  costo_egreso_inc_iva_boinv = COALESCE(egresos.costo_acumulado_ingreso_inc_iva,0), costo_egreso_boinv = COALESCE(egresos.costo_acumulado_ingreso_valor_existencia,0) ,   cantidad_egreso_t_boinv = COALESCE(egresos_t.cantidad, 0), costo_egreso_t_sin_iva_boinv = COALESCE(egresos_t.costo_acumulado_ingreso,0),  costo_egreso_t_inc_iva_boinv = COALESCE(egresos_t.costo_acumulado_ingreso_inc_iva,0), costo_egreso_t_boinv = COALESCE(egresos_t.costo_acumulado_ingreso_valor_existencia,0) ,   cantidad_egreso_baja_boinv = COALESCE(egresos_baja.cantidad, 0), costo_egreso_baja_boinv = COALESCE(egresos_baja.costo_acumulado_egreso_valor_existencia,0),  usuario_actua = 'devuser',  fecha_actua = '2025-08-24',  hora_actua = '00:27:32' FROM egresos  FULL OUTER JOIN egresos_t ON egresos.ide_bocam = egresos_t.ide_bocam AND egresos.ide_boubi = egresos_t.ide_boubi AND egresos.ide_geani = egresos_t.ide_geani FULL OUTER JOIN egresos_baja ON egresos.ide_bocam = egresos_baja.ide_bocam AND egresos.ide_boubi = egresos_baja.ide_boubi AND egresos.ide_geani = egresos_baja.ide_geani FULL OUTER JOIN param ON param.ide_geani = egresos.ide_geani AND egresos.ide_bocam = param.ide_bocam AND egresos.ide_boubi = param.ide_boubi WHERE   bodt_bodega_inventario.ide_geani = (SELECT ide_geani FROM param) AND bodt_bodega_inventario.ide_bocam = (SELECT ide_bocam FROM param) AND bodt_bodega_inventario.ide_boubi = (SELECT ide_boubi FROM param) 


